"use server";

import { prisma } from "@/lib/db";
import { auth } from "@/lib/auth";
import { revalidatePath } from "next/cache";
import { z } from "zod";
import { FieldingPosition } from "@prisma/client";

// ── Validation schemas ─────────────────────────────────────────
const playerSchema = z.object({
  firstName:       z.string().min(1, "First name is required").max(50),
  lastName:        z.string().min(1, "Last name is required").max(50),
  jerseyNumber:    z.string().max(4).optional(),
  primaryPosition: z.nativeEnum(FieldingPosition),
  notes:           z.string().max(500).optional(),
});

// ── Helpers ────────────────────────────────────────────────────
async function getTeamId() {
  const session = await auth();
  if (!session?.user?.id) throw new Error("Unauthorized");

  const team = await prisma.team.findFirst({
    where: { userId: session.user.id },
    select: { id: true },
  });

  if (!team) throw new Error("No team found");
  return team.id;
}

// ── Actions ────────────────────────────────────────────────────
export async function addPlayer(formData: FormData) {
  const teamId = await getTeamId();

  const parsed = playerSchema.safeParse({
    firstName:       formData.get("firstName"),
    lastName:        formData.get("lastName"),
    jerseyNumber:    formData.get("jerseyNumber") || undefined,
    primaryPosition: formData.get("primaryPosition"),
    notes:           formData.get("notes") || undefined,
  });

  if (!parsed.success) {
    return { error: parsed.error.errors[0]?.message ?? "Invalid data" };
  }

  // Check for duplicate jersey number
  if (parsed.data.jerseyNumber) {
    const existing = await prisma.player.findFirst({
      where: { teamId, jerseyNumber: parsed.data.jerseyNumber, isActive: true },
    });
    if (existing) {
      return { error: `Jersey #${parsed.data.jerseyNumber} is already taken` };
    }
  }

  await prisma.player.create({
    data: {
      teamId,
      ...parsed.data,
      playerStats: { create: {} },
    },
  });

  revalidatePath("/roster");
  return { success: true };
}

export async function updatePlayer(playerId: string, formData: FormData) {
  const teamId = await getTeamId();

  const parsed = playerSchema.safeParse({
    firstName:       formData.get("firstName"),
    lastName:        formData.get("lastName"),
    jerseyNumber:    formData.get("jerseyNumber") || undefined,
    primaryPosition: formData.get("primaryPosition"),
    notes:           formData.get("notes") || undefined,
  });

  if (!parsed.success) {
    return { error: parsed.error.errors[0]?.message ?? "Invalid data" };
  }

  // Check for duplicate jersey number (exclude current player)
  if (parsed.data.jerseyNumber) {
    const existing = await prisma.player.findFirst({
      where: {
        teamId,
        jerseyNumber: parsed.data.jerseyNumber,
        isActive: true,
        NOT: { id: playerId },
      },
    });
    if (existing) {
      return { error: `Jersey #${parsed.data.jerseyNumber} is already taken` };
    }
  }

  await prisma.player.update({
    where: { id: playerId, teamId },
    data: parsed.data,
  });

  revalidatePath("/roster");
  return { success: true };
}

export async function togglePlayerActive(playerId: string, isActive: boolean) {
  const teamId = await getTeamId();

  await prisma.player.update({
    where: { id: playerId, teamId },
    data: { isActive },
  });

  revalidatePath("/roster");
  return { success: true };
}

export async function deletePlayer(playerId: string) {
  const teamId = await getTeamId();

  await prisma.player.delete({
    where: { id: playerId, teamId },
  });

  revalidatePath("/roster");
  return { success: true };
}
