"use client";

import { useState, useRef } from "react";
import { FontAwesomeIcon } from "@fortawesome/react-fontawesome";
import {
  faPlus,
  faCheck,
  faXmark,
  faSpinner,
} from "@fortawesome/free-solid-svg-icons";
import { addPlayer, updatePlayer } from "@/server/actions/players";
import { FieldingPosition } from "@prisma/client";
import { cn } from "@/lib/utils";

const POSITIONS: { value: FieldingPosition; label: string }[] = [
  { value: "PITCHER",      label: "P — Pitcher" },
  { value: "CATCHER",      label: "C — Catcher" },
  { value: "FIRST_BASE",   label: "1B — First Base" },
  { value: "SECOND_BASE",  label: "2B — Second Base" },
  { value: "THIRD_BASE",   label: "3B — Third Base" },
  { value: "SHORTSTOP",    label: "SS — Shortstop" },
  { value: "LEFT_FIELD",   label: "LF — Left Field" },
  { value: "CENTER_FIELD", label: "CF — Center Field" },
  { value: "RIGHT_FIELD",  label: "RF — Right Field" },
  { value: "SHORT_FIELD",  label: "SF — Short Field" },
  { value: "EXTRA_PLAYER", label: "EP — Extra Player" },
  { value: "BENCH",        label: "Bench" },
];

interface Player {
  id: string;
  firstName: string;
  lastName: string;
  jerseyNumber: string | null;
  primaryPosition: FieldingPosition;
  notes: string | null;
}

interface PlayerFormProps {
  player?: Player;
  onClose?: () => void;
}

export function PlayerForm({ player, onClose }: PlayerFormProps) {
  const isEditing = !!player;
  const formRef = useRef<HTMLFormElement>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const [open, setOpen] = useState(isEditing);

  const handleSubmit = async (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    setError("");
    setLoading(true);

    const formData = new FormData(e.currentTarget);

    const result = isEditing
      ? await updatePlayer(player.id, formData)
      : await addPlayer(formData);

    setLoading(false);

    if (result?.error) {
      setError(result.error);
    } else {
      formRef.current?.reset();
      if (isEditing && onClose) onClose();
      if (!isEditing) setOpen(false);
    }
  };

  if (!isEditing && !open) {
    return (
      <button
        onClick={() => setOpen(true)}
        className="flex items-center gap-2 rounded-lg px-4 py-2 text-sm font-bold transition-opacity hover:opacity-80"
        style={{
          background: "var(--color-text-brand)",
          color: "#000",
          fontFamily: "var(--font-display)",
          fontSize: "0.9rem",
          letterSpacing: "0.05em",
          border: "none",
          cursor: "pointer",
        }}
      >
        <FontAwesomeIcon icon={faPlus} style={{ width: 12, height: 12 }} />
        ADD PLAYER
      </button>
    );
  }

  return (
    <div className={cn("card mb-4", !isEditing && "card-brand")}>
      <div className="mb-4 flex items-center justify-between">
        <h3
          style={{
            fontFamily: "var(--font-display)",
            fontWeight: 700,
            fontSize: "1.1rem",
            color: "var(--color-text-primary)",
            margin: 0,
          }}
        >
          {isEditing ? "Edit Player" : "Add New Player"}
        </h3>
        {(isEditing ? onClose : () => setOpen(false)) && (
          <button
            onClick={isEditing ? onClose : () => setOpen(false)}
            style={{
              background: "none",
              border: "none",
              color: "var(--color-text-muted)",
              cursor: "pointer",
            }}
          >
            <FontAwesomeIcon icon={faXmark} style={{ width: 16, height: 16 }} />
          </button>
        )}
      </div>

      <form ref={formRef} onSubmit={handleSubmit}>
        <div className="grid grid-cols-1 gap-4 md:grid-cols-2">
          {/* First Name */}
          <div>
            <label className="field-label" htmlFor="firstName">First Name</label>
            <input
              id="firstName"
              name="firstName"
              className="input"
              placeholder="e.g. Marcus"
              defaultValue={player?.firstName}
              required
            />
          </div>

          {/* Last Name */}
          <div>
            <label className="field-label" htmlFor="lastName">Last Name</label>
            <input
              id="lastName"
              name="lastName"
              className="input"
              placeholder="e.g. Johnson"
              defaultValue={player?.lastName}
              required
            />
          </div>

          {/* Jersey Number */}
          <div>
            <label className="field-label" htmlFor="jerseyNumber">Jersey #</label>
            <input
              id="jerseyNumber"
              name="jerseyNumber"
              className="input"
              placeholder="e.g. 12"
              defaultValue={player?.jerseyNumber ?? ""}
              maxLength={4}
            />
          </div>

          {/* Position */}
          <div>
            <label className="field-label" htmlFor="primaryPosition">Primary Position</label>
            <select
              id="primaryPosition"
              name="primaryPosition"
              className="input"
              defaultValue={player?.primaryPosition ?? "BENCH"}
              style={{ cursor: "pointer" }}
            >
              {POSITIONS.map((p) => (
                <option key={p.value} value={p.value}>
                  {p.label}
                </option>
              ))}
            </select>
          </div>

          {/* Notes */}
          <div className="md:col-span-2">
            <label className="field-label" htmlFor="notes">Notes (optional)</label>
            <input
              id="notes"
              name="notes"
              className="input"
              placeholder="e.g. Lefty batter, strong arm"
              defaultValue={player?.notes ?? ""}
            />
          </div>
        </div>

        {/* Error */}
        {error && (
          <p className="mt-3 text-sm font-medium" style={{ color: "var(--color-danger-400)" }}>
            ⚠ {error}
          </p>
        )}

        {/* Actions */}
        <div className="mt-4 flex gap-3">
          <button
            type="submit"
            disabled={loading}
            className="flex items-center gap-2 rounded-lg px-4 py-2 text-sm font-bold transition-opacity hover:opacity-80 disabled:opacity-50"
            style={{
              background: "var(--color-text-brand)",
              color: "#000",
              fontFamily: "var(--font-display)",
              fontSize: "0.9rem",
              letterSpacing: "0.05em",
              border: "none",
              cursor: "pointer",
            }}
          >
            {loading ? (
              <FontAwesomeIcon icon={faSpinner} spin style={{ width: 14, height: 14 }} />
            ) : (
              <FontAwesomeIcon icon={faCheck} style={{ width: 14, height: 14 }} />
            )}
            {isEditing ? "SAVE CHANGES" : "ADD PLAYER"}
          </button>

          <button
            type="button"
            onClick={isEditing ? onClose : () => setOpen(false)}
            className="rounded-lg px-4 py-2 text-sm font-semibold transition-colors"
            style={{
              background: "rgba(255,255,255,0.06)",
              color: "var(--color-text-muted)",
              border: "none",
              cursor: "pointer",
              fontFamily: "var(--font-body)",
            }}
          >
            Cancel
          </button>
        </div>
      </form>
    </div>
  );
}
